head.b:skin:
/* Kaydırma çubuğunun bütünü */
::-webkit-scrollbar {
  width: 5px;               /* Çubuğun genişliği */
}

/* Kaydırma çubuğunun arka planı (yolu) */
::-webkit-scrollbar-track {
  background: #141414;      /* Açık gri arka plan */
}

/* Hareket eden tutamaç kısmı */
::-webkit-scrollbar-thumb {
  background: #ff0000;         /* Koyu gri tutamaç */
  border-radius: 10px;      /* Köşeleri yuvarlar */
}

/* Tutamaç üzerine gelince rengi değiştirme */
::-webkit-scrollbar-thumb:hover {
  background: red;         /* Üzerine gelince daha koyu olur */
}


    /* --- ULTIMATE CSS DEĞİŞKENLERİ --- */

    :root { 

        --primary: #E50914; 

        --primary-glow: rgba(229, 9, 20, 0.5);

        --dizi-color: #9b59b6; 

        --bg-body: #141414; 

        --bg-card: #1f1f1f;

        --bg-glass: rgba(20, 20, 20, 0.95); 

        --text-main: #f5f5f5;

        --text-sec: #b0b0b0;

        --radius: 12px;

        --header-h: 80px; 

    }



    body { background-color: var(--bg-body); color: var(--text-main); font-family: 'Outfit', sans-serif; margin: 0; padding: 0; padding-top: var(--header-h); -webkit-font-smoothing: antialiased; position: relative;}

    a { text-decoration: none; color: inherit; transition: 0.3s ease; }

    ul { list-style: none; padding: 0; margin: 0; }

    * { box-sizing: border-box; outline: none; }

    

    /* --- HEADER --- */

    header { 

        background: var(--bg-glass); 

        height: var(--header-h); 

        padding: 0 4%; 

        position: fixed; top: 0; left: 0; right: 0; 

        z-index: 9999; 

        display: flex; align-items: center; justify-content: space-between; 

        border-bottom: 1px solid rgba(255,255,255,0.05);

        box-shadow: 0 5px 20px rgba(0,0,0,0.5);

        backdrop-filter: blur(10px);

    }

    

    .logo h1 { font-size: 26px; color: var(--primary); text-transform: uppercase; font-weight: 800; letter-spacing: -0.5px; margin: 0; text-shadow: 0 0 25px var(--primary-glow); }

    

    /* --- YENİ MENÜ SİSTEMİ --- */

    .nav-menu { height: 100%; display: flex; align-items: center; }

    .nav-list { display: flex; gap: 5px; height: 100%; align-items: center; }

    

    .nav-item { position: relative; height: 100%; display: flex; align-items: center; }

    

    .nav-link { 

        padding: 0 15px; 

        height: 100%;

        display: flex; align-items: center; gap: 8px;

        font-size: 14px; font-weight: 600; color: #ccc; 

        text-transform: uppercase; letter-spacing: 0.5px;

        transition: 0.3s;

        border-bottom: 2px solid transparent;

    }

    

    .nav-link i { font-size: 12px; color: #666; transition: 0.3s; }

    

    .nav-item:hover .nav-link { color: #fff; text-shadow: 0 0 10px rgba(255,255,255,0.3); }

    .nav-item:hover .nav-link i { color: var(--primary); }

    

    /* DROPDOWN (AÇILIR MENÜ) */

    .dropdown {

        position: absolute;

        top: 100%; left: 0;

        width: 220px;

        background: var(--bg-card);

        border: 1px solid rgba(255,255,255,0.1);

        border-top: 3px solid var(--primary);

        border-radius: 0 0 12px 12px;

        box-shadow: 0 10px 30px rgba(0,0,0,0.5);

        opacity: 0; visibility: hidden;

        transform: translateY(10px);

        transition: all 0.3s cubic-bezier(0.68, -0.55, 0.27, 1.55);

        padding: 10px 0;

        z-index: 100;

    }

    

    .nav-item:hover .dropdown { opacity: 1; visibility: visible; transform: translateY(0); }

    

    .dropdown li a {

        display: block;

        padding: 10px 20px;

        font-size: 13px; font-weight: 500; color: #bbb;

        border-left: 3px solid transparent;

    }

    

    .dropdown li a:hover {

        background: rgba(255,255,255,0.05);

        color: #fff;

        border-left-color: var(--primary);

        padding-left: 25px;

    }



    /* ARAMA VE SAĞ ALAN - GÜNCELLENMİŞ */

    .right-area { display: flex; align-items: center; gap: 15px; position: relative; }



    .classic-search-box {

        position: relative;

        width: 250px;

        height: 40px;

        background: rgba(255,255,255,0.1);

        border-radius: 50px;

        border: 1px solid rgba(255,255,255,0.1);

        transition: 0.3s;

        display: flex; align-items: center;

        z-index: 10001; /* Sonuçlar için üstte kalmalı */

    }

    .classic-search-box:focus-within {

        background: rgba(0,0,0,0.5);

        border-color: var(--primary);

        width: 300px;

        box-shadow: 0 0 15px rgba(229,9,20,0.2);

    }

    .classic-search-box form { width: 100%; height: 100%; display: flex; }

    .classic-search-box input {

        width: 100%; height: 100%;

        background: transparent; border: none;

        padding: 0 15px; color: #fff; font-size: 13px;

        font-family: inherit;

    }

    .classic-search-box button {

        background: transparent; border: none;

        color: #aaa; padding-right: 15px; cursor: pointer;

        font-size: 14px; transition: 0.3s;

    }

    .classic-search-box button:hover { color: var(--primary); }

    

    /* CANLI ARAMA SONUÇLARI TASARIMI */

    .search-results-box {

        position: absolute;

        top: 100%;

        right: 0; /* Sağa yaslı */

        width: 300px;

        background: #1a1a1a;

        border: 1px solid rgba(255,255,255,0.1);

        border-radius: 0 0 12px 12px;

        box-shadow: 0 15px 40px rgba(0,0,0,0.9);

        z-index: 9999;

        margin-top: 5px;

        max-height: 0;

        overflow: hidden;

        opacity: 0;

        transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);

    }

    

    .search-results-box.active {

        max-height: 400px;

        opacity: 1;

        padding: 10px 0;

        overflow-y: auto;

    }

    

    .live-item {

        display: flex;

        align-items: center;

        gap: 12px;

        padding: 10px 15px;

        border-bottom: 1px solid rgba(255,255,255,0.05);

        cursor: pointer;

        transition: 0.2s;

        text-decoration: none;

    }

    .live-item:last-child { border-bottom: none; }

    .live-item:hover { background: rgba(255,255,255,0.1); padding-left:20px; }

    

    .live-thumb {

        width: 45px; height: 65px;

        border-radius: 4px;

        object-fit: cover;

        background: #333;

        flex-shrink: 0;

    }

    

    .live-info { flex: 1; overflow: hidden; }

    .live-title {

        font-size: 13px; color: #fff; font-weight: 600;

        margin-bottom: 3px;

        white-space: nowrap; overflow: hidden; text-overflow: ellipsis;

    }

    .live-meta { font-size: 10px; color: var(--primary); font-weight: 700; text-transform: uppercase; }

    .live-loading { padding: 15px; text-align: center; color: #888; font-size: 12px; }



    .menu-toggle { display: none; font-size: 24px; cursor: pointer; color: #fff; }



    /* --- SLIDER --- */

    .main-slider { 

        position: relative; 

        width: 100%; 

        height: 75vh; 

        margin-top: 0; 

        margin-bottom: 40px; 

        overflow: hidden; 

        z-index: 1; 

        mask-image: linear-gradient(to bottom, black 85%, transparent 100%);

        -webkit-mask-image: linear-gradient(to bottom, black 85%, transparent 100%);

    }

    

    .slider-wrapper { display: flex; width: 100%; height: 100%; transition: transform 0.8s cubic-bezier(0.22, 1, 0.36, 1); cursor: grab; }

    .slide-item { min-width: 100%; height: 100%; position: relative; overflow: hidden; }

    

    @keyframes zoomEffect {

        0% { transform: scale(1); }

        100% { transform: scale(1.15); }

    }

    

    .slide-bg { 

        width: 100%; height: 100%; object-fit: cover; 

        position: absolute; top: 0; left: 0; z-index: 1; 

        animation: zoomEffect 20s infinite alternate linear; 

    }

    

    .slide-overlay { 

        position: absolute; inset: 0; 

        background: radial-gradient(circle at 70% 50%, transparent 0%, rgba(20,20,20,0.6) 50%, var(--bg-body) 100%),

                    linear-gradient(to top, var(--bg-body) 10%, rgba(20,20,20,0.6) 40%, transparent 100%);

        z-index: 2; 

    }

    

    .slide-content { 

        position: absolute; bottom: 120px; left: 6%; z-index: 3; 

        max-width: 700px; opacity: 0; transform: translateY(30px); 

        transition: 0.8s cubic-bezier(0.22, 1, 0.36, 1) 0.3s; 

    }

    .slide-item.active .slide-content { opacity: 1; transform: translateY(0); }

    

    .slide-meta { display: flex; gap: 12px; align-items: center; margin-bottom: 20px; opacity: 0; transform: translateY(20px); transition: 0.8s ease 0.4s; }

    .slide-item.active .slide-meta { opacity: 1; transform: translateY(0); }

    

    .slide-badge { 

        background: rgba(255,255,255,0.15); color: #fff; padding: 5px 12px; 

        font-size: 11px; font-weight: 700; border-radius: 4px; 

        backdrop-filter: blur(5px); border: 1px solid rgba(255,255,255,0.1);

        text-transform: uppercase; letter-spacing: 0.5px;

    }

    .slide-rating { 

        color: #f5c518; font-weight: 800; font-size: 16px; 

        display: flex; align-items: center; gap: 6px; 

        text-shadow: 0 2px 10px rgba(0,0,0,0.5);

    }

    .slide-genre { color: #ddd; font-size: 15px; font-weight: 600; text-transform: capitalize; text-shadow: 0 2px 4px rgba(0,0,0,0.8); }

    

    .slide-title { 

        font-size: 4.5rem; margin: 0 0 20px 0; line-height: 1; 

        font-weight: 900; color: #fff;

        text-shadow: 0 10px 40px rgba(0,0,0,0.9); letter-spacing: -2px; 

        opacity: 0; transform: translateY(20px); transition: 0.8s ease 0.5s;

    }

    .slide-item.active .slide-title { opacity: 1; transform: translateY(0); }

    

    .slide-desc { 

        font-size: 1.15rem; color: #ccc; line-height: 1.6; margin-bottom: 35px; 

        max-width: 600px; display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; 

        text-shadow: 0 2px 5px rgba(0,0,0,0.8);

        opacity: 0; transform: translateY(20px); transition: 0.8s ease 0.6s;

    }

    .slide-item.active .slide-desc { opacity: 1; transform: translateY(0); }

    

    .slide-buttons { display: flex; gap: 20px; opacity: 0; transform: translateY(20px); transition: 0.8s ease 0.7s; }

    .slide-item.active .slide-buttons { opacity: 1; transform: translateY(0); }

    

    .btn-play { 

        background: var(--primary); color: #fff; 

        padding: 16px 40px; border-radius: 8px; font-weight: 700; 

        display: inline-flex; align-items: center; gap: 12px; font-size: 17px; 

        transition: 0.3s; border: none; 

        box-shadow: 0 10px 30px rgba(229, 9, 20, 0.4);

    }

    .btn-play:hover { background: #ff0f1f; transform: scale(1.05); box-shadow: 0 15px 40px rgba(229, 9, 20, 0.6); }

    

    .btn-detail { 

        background: rgba(255,255,255,0.1); color: #fff; 

        padding: 16px 40px; border-radius: 8px; font-weight: 600; font-size: 17px; 

        backdrop-filter: blur(15px); display: inline-flex; align-items: center; gap: 12px; 

        transition: 0.3s; border: 1px solid rgba(255,255,255,0.2); 

    }

    .btn-detail:hover { background: rgba(255,255,255,0.25); transform: scale(1.05); border-color: #fff; }

    

    .slider-nav { position: absolute; bottom: 50px; right: 50px; top: auto; transform: none; z-index: 10; display: flex; gap: 15px; }

    .nav-btn { width: 60px; height: 60px; border-radius: 50%; background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); color: #fff; display: flex; align-items: center; justify-content: center; cursor: pointer; transition: 0.3s; backdrop-filter: blur(5px); font-size: 20px; }

    .nav-btn:hover { background: #fff; color: #000; transform: scale(1.1); }



    /* --- LAYOUTS --- */

    .container { padding: 0 4% 50px; }

    .section-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 25px; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 15px; }

    .section-title { font-size: 22px; font-weight: 700; color: #fff; letter-spacing: 0.5px; border-left: 3px solid var(--primary); padding-left: 15px; }

    .section-link { font-size: 12px; color: var(--primary); font-weight: 700; text-transform: uppercase; letter-spacing: 1px; }



    /* YATAY LİSTE */

    .horizontal-wrapper { position: relative; width: 100%; margin-bottom: 40px; }

    

    .horizontal-list {

        display: flex;

        gap: 20px;

        overflow-x: auto;

        padding-bottom: 20px;

        scroll-behavior: smooth;

        -webkit-overflow-scrolling: touch;

        scrollbar-width: none; 

    }

    .horizontal-list::-webkit-scrollbar { display: none; }

    

    .horizontal-list .movie-card {

        min-width: 200px;

        width: 200px;

        flex-shrink: 0;

    }



    .scroll-btn {

        position: absolute;

        top: 45%; 

        transform: translateY(-50%);

        width: 50px; height: 50px;

        border-radius: 50%;

        background: rgba(0,0,0,0.6);

        color: #fff;

        border: 1px solid rgba(255,255,255,0.2);

        display: flex; align-items: center; justify-content: center;

        cursor: pointer;

        z-index: 20;

        backdrop-filter: blur(5px);

        transition: 0.3s;

        opacity: 0; visibility: hidden;

    }

    .horizontal-wrapper:hover .scroll-btn { opacity: 1; visibility: visible; }

    .scroll-btn:hover { background: var(--primary); border-color: var(--primary); transform: translateY(-50%) scale(1.1); }

    .scroll-btn.left { left: -25px; }

    .scroll-btn.right { right: -25px; }



    /* NORMAL IZGARA */

    .grid-movies { display: grid; grid-template-columns: repeat(auto-fill, minmax(190px, 1fr)); gap: 30px 20px; }

    

    /* KART TASARIMI */

    .movie-card { position: relative; aspect-ratio: 2/3; border-radius: var(--radius); overflow: hidden; background: var(--bg-card); transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1); box-shadow: 0 5px 15px rgba(0,0,0,0.2); border: 1px solid rgba(255,255,255,0.05); cursor: pointer; }

    .movie-card:hover { transform: translateY(-8px); box-shadow: 0 15px 40px rgba(0,0,0,0.5); z-index: 5; border-color: rgba(255,255,255,0.2); }

    .poster-img { width: 100%; height: 100%; object-fit: cover; transition: 0.4s; }

    .movie-card:hover .poster-img { opacity: 0.3; transform: scale(1.05); filter: blur(3px); }

    .play-icon { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%) scale(0.5); width: 60px; height: 60px; background: rgba(229, 9, 20, 0.9); border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 24px; color: #fff; opacity: 0; transition: 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); box-shadow: 0 0 20px rgba(229, 9, 20, 0.6); }

    .movie-card:hover .play-icon { transform: translate(-50%, -50%) scale(1); opacity: 1; }

    .card-info { position: absolute; inset: 0; padding: 15px; display: flex; flex-direction: column; justify-content: flex-end; opacity: 0; transition: 0.3s; }

    .movie-card:hover .card-info { opacity: 1; }

    .card-title { font-weight: 800; font-size: 15px; margin-bottom: 8px; line-height: 1.2; color:#fff; text-shadow: 0 2px 5px #000; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }

    .card-meta { display: flex; justify-content: space-between; align-items: center; font-size: 11px; color: #ddd; font-weight: 600; }

    .card-year { background: rgba(255,255,255,0.2); padding: 2px 8px; border-radius: 4px; backdrop-filter: blur(2px); }

    .card-genre { color: var(--primary); text-transform: uppercase; font-size: 10px; font-weight: 700; letter-spacing: 0.5px; }

    

    .type-badge { position: absolute; top: 12px; right: 12px; padding: 5px 12px; border-radius: 8px; font-size: 10px; font-weight: 900; color: #fff; z-index: 10; text-transform: uppercase; letter-spacing: 0.5px; box-shadow: 0 4px 15px rgba(0,0,0,0.4); pointer-events: none; backdrop-filter: blur(8px); border: 1px solid rgba(255,255,255,0.2); }

    .type-badge.film { background: linear-gradient(135deg, rgba(229,9,20,0.8), rgba(184,2,11,0.9)); box-shadow: 0 4px 15px rgba(229,9,20,0.3); }

    .type-badge.dizi { background: linear-gradient(135deg, rgba(155, 89, 182, 0.8), rgba(142, 68, 173, 0.9)); box-shadow: 0 4px 15px rgba(155, 89, 182, 0.3); }

    

    .imdb-badge { position: absolute; top: 12px; left: 12px; z-index: 10; background: #f5c518; color: #000; font-weight: 800; font-size: 11px; padding: 4px 8px; border-radius: 4px; display: flex; align-items: center; gap: 4px; box-shadow: 0 4px 15px rgba(245, 197, 24, 0.3); opacity: 0; transition: opacity 0.5s ease; }

    .imdb-badge.loaded { opacity: 1; }



    /* --- YENİ DİL ROZETLERİ (GELİŞTİRİLMİŞ) --- */

    .lang-badges { position: absolute; top: 45px; left: 10px; display: flex; flex-direction: column; gap: 6px; z-index: 10; }

    

    .lang-badge { 

        font-size: 10px; padding: 4px 8px; border-radius: 4px; font-weight: 800; 

        text-transform: uppercase; color: #fff; display: inline-flex; align-items: center; gap: 5px; 

        letter-spacing: 0.5px; box-shadow: 0 4px 10px rgba(0,0,0,0.5); 

        text-shadow: 0 1px 2px rgba(0,0,0,0.3);

    }

    .lang-badge i { font-size: 11px; }



    /* DUBLAJ - Mavi/Turkuaz tonu, daha parlak */

    .lang-badge.dub { 

        background: linear-gradient(45deg, #FF0000, #FF0000);

        

    }

    

    /* ALTYAZI - Yeşil tonu, daha parlak */

    .lang-badge.sub { 

        background: linear-gradient(45deg, #11998e, #018749); 

        

    }

    

    .load-more-container { text-align: center; margin-top: 50px; }

    .btn-load-more { background: var(--bg-card); border: 1px solid rgba(255,255,255,0.1); color: #fff; padding: 15px 40px; border-radius: 50px; font-weight: 700; text-transform: uppercase; letter-spacing: 1px; cursor: pointer; transition: 0.3s; font-size: 14px; }

    .btn-load-more:hover { background: var(--primary); border-color: var(--primary); transform: translateY(-3px); box-shadow: 0 10px 30px rgba(229,9,20,0.3); }

    .btn-load-more i { margin-right: 8px; }

    .btn-load-more.loading { opacity: 0.7; cursor: wait; pointer-events: none; }



    /* Post Content Styles */

    .post-container { max-width: 1400px; margin: 30px auto; padding: 0 20px; }

    .player-wrapper { position: relative; z-index: 20; }

    .player-box { position: relative; width: 100%; padding-bottom: 56.25%; background: #000; border-radius: 16px; overflow: hidden; box-shadow: 0 0 80px rgba(0,0,0,0.6); border: 1px solid #333; margin-bottom: 20px; }

    .player-box iframe { position: absolute; top: 0; left: 0; width: 100%; height: 100%; border: 0; }

    .content-grid { display: grid; grid-template-columns: 1fr 350px; gap: 50px; }

    .movie-header h1 { font-size: 38px; margin: 0 0 10px 0; color: #fff; line-height: 1.1; font-weight: 800; letter-spacing: -1px; }

    .meta-row { display: flex; flex-wrap: wrap; gap: 12px; margin-bottom: 30px; align-items: center; }

    .meta-tag { display: inline-flex; align-items: center; gap: 8px; background: rgba(255, 255, 255, 0.05); border: 1px solid rgba(255, 255, 255, 0.1); padding: 8px 16px; border-radius: 50px; font-size: 13px; font-weight: 600; color: #e5e5e5; transition: 0.3s ease; text-transform: uppercase; letter-spacing: 0.5px; }

    .meta-tag:hover { background: rgba(255, 255, 255, 0.15); border-color: var(--primary); color: #fff; transform: translateY(-2px); }

    .meta-tag i { color: var(--primary); font-size: 14px; }

    .synopsis { background: var(--bg-card); padding: 35px; border-radius: 12px; color: var(--text-sec); line-height: 1.8; font-size: 16px; border: 1px solid rgba(255,255,255,0.05); }

    .synopsis h3 { color: #fff; margin-top: 0; font-size: 20px; border-bottom: 1px solid rgba(255,255,255,0.1); padding-bottom: 15px; margin-bottom: 15px; font-weight: 700; }

    .sidebar-sticky { position: sticky; top: 100px; }

    .info-card { background: var(--bg-card); border-radius: 12px; padding: 25px; border: 1px solid rgba(255,255,255,0.05); }

    .info-row { display: flex; justify-content: space-between; border-bottom: 1px solid rgba(255,255,255,0.05); padding: 15px 0; }

    .info-row:last-child { border: none; }

    .label { color: #777; font-size: 13px; font-weight: 600; text-transform: uppercase; }

    .value { color: #eee; font-weight: 600; text-align: right; font-size: 14px; }

    .action-btn { display: block; width: 100%; background: #333; color: #fff; text-align: center; padding: 14px; border-radius: 8px; margin-top: 10px; font-weight: 600; transition: 0.3s; }

    .action-btn:hover { background: #444; }

    .action-btn.primary { background: var(--primary); }

    .action-btn.primary:hover { background: #c00811; }

    .related-area { margin-top: 60px; }

    .related-title { font-size: 24px; font-weight: 700; margin-bottom: 30px; border-left: 4px solid var(--primary); padding-left: 20px; color: #fff; }



    /* Footer */

    .site-footer { background: #080808; border-top: 1px solid #1a1a1a; padding: 60px 0 30px; margin-top: 100px; }

    .footer-content { max-width: 1400px; margin: 0 auto; padding: 0 4%; display: grid; grid-template-columns: 1fr 1fr; gap: 40px; margin-bottom: 40px; }

    .footer-brand h2 { color: var(--primary); font-size: 28px; margin: 0 0 15px 0; font-weight: 900; }

    .footer-text { color: #666; font-size: 14px; line-height: 1.6; max-width: 400px; }

    .footer-links { display: flex; gap: 25px; justify-content: flex-end; }

    .footer-links a { color: #888; font-size: 14px; font-weight: 500; }

    .footer-links a:hover { color: #fff; }

    .copyright { text-align: center; border-top: 1px solid #1a1a1a; padding-top: 25px; color: #444; font-size: 13px; }

    .hidden-thumb { display: none !important; }

    .post-content img:first-child { display: none !important; }



    /* Comments Styles */

    .comments-area { margin-top: 50px; background: var(--bg-card); padding: 35px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.05); }

    .comments-title { font-size: 22px; color: #eee; margin-bottom: 30px; font-weight: 700; border-left: 4px solid var(--primary); padding-left: 15px; }

    .comment-item { display: flex; gap: 20px; margin-bottom: 30px; border-bottom: 1px solid rgba(255,255,255,0.05); padding-bottom: 30px; }

    .comment-item:last-child { border: none; margin: 0; padding: 0; }

    .avatar-box img { width: 45px; height: 45px; border-radius: 50%; object-fit: cover; border: 2px solid #333; }

    .comment-content { flex: 1; }

    .comment-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }

    .user-name { font-weight: 700; color: #fff; font-size: 15px; display:flex; align-items:center; gap:8px;}

    .user-name a { pointer-events: none; text-decoration: none; color: inherit; cursor: default; }

    .comment-date { font-size: 11px; color: #666; font-weight: 600; text-transform: uppercase; }

    .admin-badge { background: var(--primary); color: #fff; font-size: 9px; padding: 2px 6px; border-radius: 3px; text-transform: uppercase; font-weight: 800; display: inline-flex; align-items: center; gap: 3px; }

    .comment-body { color: #ccc; font-size: 14px; line-height: 1.6; background: rgba(255,255,255,0.03); padding: 15px; border-radius: 0 10px 10px 10px; border: 1px solid rgba(255,255,255,0.05); }

    .comment-actions { margin-top: 15px; text-align: right; }

    .comment-reply { font-size: 11px; color: var(--primary); background: transparent; padding: 6px 15px; border-radius: 20px; font-weight: 700; cursor: pointer; text-transform: uppercase; transition: 0.3s; display: inline-block; border: 1px solid var(--primary); position: relative; z-index: 5; }

    .comment-reply:hover { background: var(--primary); color: #fff; text-decoration: none; box-shadow: 0 5px 15px rgba(229, 9, 20, 0.4); }

    .comment-form-container { margin-top: 40px; border-top: 1px solid rgba(255,255,255,0.1); padding-top: 30px; }

    .comment-form-container h4 { color: #ddd; font-size: 18px; margin-bottom: 15px; }

    iframe.blogger-iframe-colorize, iframe.blogger-comment-from-post { width: 100% !important; min-height: 250px !important; border: 1px solid #333 !important; border-radius: 12px; background: #fff; filter: invert(0.92) hue-rotate(180deg); }



    /* --- RESPONSIVE --- */

    @media (max-width: 1024px) {

        .content-grid { grid-template-columns: 1fr; }

        .sidebar-sticky { position: static; margin-top: 30px; }

    }

    @media (max-width: 768px) {

        /* MOBİL MENÜ DÜZENLEMESİ */

        .nav-menu { position: fixed; top: var(--header-h); left: 0; width: 100%; height: auto; background: var(--bg-body); border-bottom: 1px solid #222; box-shadow: 0 10px 30px rgba(0,0,0,0.5); display: none; flex-direction: column; padding: 20px 0; align-items: flex-start; }

        .nav-menu.active { display: flex; }

        .nav-list { flex-direction: column; width: 100%; align-items: flex-start; gap: 0; }

        .nav-item { width: 100%; display: block; height: auto; border-bottom: 1px solid rgba(255,255,255,0.05); }

        .nav-link { padding: 15px 30px; width: 100%; }

        

        /* Mobil Dropdown */

        .dropdown { position: static; width: 100%; visibility: visible; opacity: 1; transform: none; box-shadow: none; border: none; background: rgba(0,0,0,0.2); display: none; padding: 0; }

        .nav-item.active-mobile .dropdown { display: block; }

        .dropdown li a { padding-left: 50px; }



        .menu-toggle { display: block; order: 3; margin-left: 20px; }

        .right-area { margin-left: auto; }

        .classic-search-box { width: 150px; }

        .classic-search-box:focus-within { width: 200px; }

        

        .grid-movies { grid-template-columns: repeat(2, 1fr); gap: 15px; }

        .movie-card { aspect-ratio: 2/3.2; }



        /* MOBİL YATAY KAYDIRMA */

        .scroll-btn { display: none !important; } /* Mobilde okları gizle */

        .horizontal-list { padding-bottom: 10px; }

        .horizontal-list .movie-card { min-width: 150px; width: 150px; }

        

        /* MOBİL SLIDER AYARLARI */

        .main-slider { height: 80vh; margin-top: 0; margin-bottom: 20px; }

        .slide-content { bottom: 60px; left: 5%; width: 90%; max-width: 90%; text-align: left; }

        .slide-title { font-size: 2.8rem; margin-bottom: 10px; }

        .slide-desc { font-size: 1rem; -webkit-line-clamp: 3; margin-bottom: 20px; display: -webkit-box; }

        .slide-meta { margin-bottom: 15px; justify-content: flex-start; }

        .slide-buttons { justify-content: flex-start; }

        

        .slider-nav { display: none !important; } 

        

        .btn-play, .btn-detail { padding: 12px 20px; font-size: 14px; }

        .footer-content { grid-template-columns: 1fr; text-align: center; }

        .footer-links { justify-content: center; margin-top: 20px; }

        .container { padding-top: 10px; }

    }

b:if.script:
        //

            document.addEventListener("DOMContentLoaded", function() {

                var container = document.getElementById('hero-slider');

                

                function renderDemoSlider() {

                    var demoSlides = [

                        {title: "Sinema Dünyası", desc: "En yeni filmleri ve dizileri 4K kalitesinde izleyin. Sinema keyfi evinizde.", img: "https://images.unsplash.com/photo-1626814026160-2237a95fc5a0?ixlib=rb-1.2.1&auto=format&fit=crop&w=1600&q=80", link: "/search", rating: "9.5", genre: "Sinema"},

                        {title: "Dizileri Keşfet", desc: "Soluksuz izleyeceğiniz en popüler diziler burada. Hemen maratona başla.", img: "https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?ixlib=rb-1.2.1&auto=format&fit=crop&w=1600&q=80", link: "/search/label/Dizi", rating: "8.9", genre: "Dizi"},

                        {title: "Aksiyon Filmleri", desc: "Adrenalin dolu aksiyon filmleri ile heyecana ortak ol.", img: "https://images.unsplash.com/photo-1598899134739-24c46f58b8c0?ixlib=rb-1.2.1&auto=format&fit=crop&w=1600&q=80", link: "/search/label/Aksiyon", rating: "9.1", genre: "Aksiyon"}

                    ];

                    

                    var html = "";

                    demoSlides.forEach((slide, i) => {

                        var active = i === 0 ? " active" : "";

                        html += `

                        <div class="slide-item${active}">

                            <img class="slide-bg" src="${slide.img}" alt="${slide.title}">

                            <div class="slide-overlay"></div>

                            <div class="slide-content">

                                <div class="slide-meta">

                                    <span class="slide-badge">Öne Çıkan</span>

                                    <span class="slide-rating"><i class="fas fa-star"></i> ${slide.rating}</span>

                                    <span class="slide-genre">${slide.genre}</span>

                                </div>

                                <h2 class="slide-title">${slide.title}</h2>

                                <div class="slide-desc">${slide.desc}</div>

                                <div class="slide-buttons">

                                    <a class="btn-play" href="${slide.link}"><i class="fas fa-play"></i> Hemen İzle</a>

                                    <a class="btn-detail" href="${slide.link}"><i class="fas fa-info-circle"></i> Detay</a>

                                </div>

                            </div>

                        </div>`;

                    });

                    container.innerHTML = html;

                    initSlider(3);

                }



                // FETCH DATA

                fetch('/feeds/posts/default/-/Slider?alt=json&max-results=10')

                .then(res => res.json())

                .then(data => {

                    if(!data.feed.entry || data.feed.entry.length === 0) {

                        renderDemoSlider();

                        return;

                    }

                    

                    var entries = data.feed.entry;

                    entries.sort(() => Math.random() - 0.5);

                    entries = entries.slice(0, 5);



                    var sliderHTML = "";

                    

                    entries.forEach((entry, index) => {

                        var title = entry.title.$t;

                        var link = entry.link.find(l => l.rel == 'alternate').href;

                        

                        var img = "https://via.placeholder.com/1600x900";

                        if(entry.media$thumbnail) {

                            img = entry.media$thumbnail.url.replace(/\/s[0-9]+(-c)?\//, '/s0/');

                        }

                        if(entry.content && entry.content.$t) {

                             var doc = new DOMParser().parseFromString(entry.content.$t, 'text/html');

                             var firstImg = doc.querySelector('img');

                             if(firstImg) img = firstImg.src;

                        }

                        

                        var snippet = entry.summary ? entry.summary.$t.substring(0, 160) + "..." : "";

                        var activeClass = index === 0 ? " active" : "";

                        

                        var imdbRating = "";

                        var category = entry.category && entry.category.length > 0 ? entry.category[0].term : "Film";



                        if(entry.content && entry.content.$t) {

                            var doc = new DOMParser().parseFromString(entry.content.$t, 'text/html');

                            var labels = doc.querySelectorAll('.label');

                            labels.forEach(lbl => {

                                if(lbl.textContent.trim().toUpperCase() === 'IMDB' || lbl.textContent.trim() === 'Puan') {

                                    var val = lbl.nextElementSibling;

                                    if(val && val.classList.contains('value')) {

                                        imdbRating = val.textContent.trim();

                                    }

                                }

                            });

                        }

                        if(imdbRating === "") imdbRating = "";



                        sliderHTML += `

                        <div class="slide-item${activeClass}">

                            <img class="slide-bg" src="${img}" alt="${title}">

                            <div class="slide-overlay"></div>

                            <div class="slide-content">

                                <div class="slide-meta">

                                    <span class="slide-badge">HD</span>

                                    ${imdbRating ? `<span class="slide-rating"><i class="fas fa-star"></i> ${imdbRating}</span>` : ''}

                                    <span class="slide-genre">${category}</span>

                                </div>

                                <h2 class="slide-title">${title}</h2>

                                <div class="slide-desc">${snippet}</div>

                                <div class="slide-buttons">

                                    <a class="btn-play" href="${link}"><i class="fas fa-play"></i> Hemen İzle</a>

                                    <a class="btn-detail" href="${link}"><i class="fas fa-info-circle"></i> Detay</a>

                                </div>

                            </div>

                        </div>`;

                    });

                    

                    container.innerHTML = sliderHTML;

                    initSlider(entries.length);

                })

                .catch(err => {

                    console.log("Slider Hatası:", err);

                    renderDemoSlider(); 

                });

            });



            // Slider & Swipe

            function initSlider(total) {

                window.currentSlide = 0;

                window.totalSlides = total;

                setInterval(() => { moveSlide(1); }, 7000); 

                

                const slider = document.getElementById('touch-slider');

                let touchStartX = 0;

                let touchEndX = 0;



                slider.addEventListener('touchstart', e => {

                    touchStartX = e.changedTouches[0].screenX;

                }, {passive: true});



                slider.addEventListener('touchend', e => {

                    touchEndX = e.changedTouches[0].screenX;

                    handleSwipe();

                }, {passive: true});



                function handleSwipe() {

                    if (touchEndX < touchStartX - 50) moveSlide(1); 

                    if (touchEndX > touchStartX + 50) moveSlide(-1); 

                }

            }



            function moveSlide(n) {

                if(typeof window.totalSlides === 'undefined' || window.totalSlides === 0) return;

                

                window.currentSlide += n;

                if(window.currentSlide >= window.totalSlides) window.currentSlide = 0;

                if(window.currentSlide < 0) window.currentSlide = window.totalSlides - 1;

                

                var wrapper = document.getElementById('hero-slider');

                wrapper.style.transform = `translateX(-${window.currentSlide * 100}%)`;

                

                var slides = document.querySelectorAll('.slide-item');

                slides.forEach(s => s.classList.remove('active'));

                slides[window.currentSlide].classList.add('active');

            }

