            // 1. MEVCUT KARTLARI DÜZENLEME FONKSİYONU

            function enrichCards(context) {

                var cards = context.querySelectorAll('.movie-card:not(.processed)');

                cards.forEach(card => {

                    card.classList.add('processed');

                    var url = card.getAttribute('data-url');

                    

                    if(url) {

                        fetch(url)

                        .then(res => res.text())

                        .then(html => {

                            var parser = new DOMParser();

                            var doc = parser.parseFromString(html, 'text/html');

                            var imdbRating = "", year = "", genre = "";

                            var labels = doc.querySelectorAll('.label');

                            

                            labels.forEach(lbl => {

                                var text = lbl.textContent.trim().toLowerCase();

                                var valNode = lbl.nextElementSibling;

                                if(valNode && valNode.classList.contains('value')) {

                                    var val = valNode.textContent.trim();

                                    if(text.includes('imdb') || text.includes('puan')) imdbRating = val;

                                    if(text.includes('yıl') || text.includes('yapım')) year = val;

                                    if(text.includes('tür') || text.includes('kategori')) {

                                        if(val.length > 12) val = val.split(',')[0] + '';

                                        genre = val;

                                    }

                                }

                            });



                            if(imdbRating) {

                                var badge = document.createElement('span');

                                badge.className = 'imdb-badge loaded';

                                badge.innerHTML = '<i class="fas fa-star"/> ' + imdbRating;

                                card.appendChild(badge);

                            }

                            if(year) {

                                var yearEl = card.querySelector('.card-year');

                                if(yearEl) yearEl.textContent = year;

                            }

                            if(genre) {

                                var genreEl = card.querySelector('.card-genre');

                                if(genreEl) genreEl.textContent = genre;

                            }

                        })

                        .catch(err => console.log('Data Fetch Error'));

                    }

                });

            }



