                                ${imdbRating ? `<span class="imdb-badge loaded"><i class="fas fa-star"></i> ${imdbRating}</span>` : ''}



                                <div class="lang-badges">

                                    ${isDub ? `<span class="lang-badge dub"><i class="fas fa-microphone"></i> DUB</span>` : ''}

                                    ${isSub ? `<span class="lang-badge sub"><i class="fas fa-closed-captioning"></i> ALT</span>` : ''}

                                </div>



                                <img class="poster-img" src="${img}" loading="lazy"/>

                                <div class="play-icon"><i class="fas fa-play"></i></div>

                                <div class="card-info">

                                    <div class="card-title">${title}</div>

                                    <div class="card-meta">

                                        <span class="card-year">${year}</span>

                                        <span class="card-genre">${genre}</span>

                                    </div>

                                </div>

                                <a href="${link}" style="position:absolute; inset:0; z-index:20;"></a>

                            </div>`;

                        });

                        containerSeries.innerHTML = html;

                    })

                    .catch(err => console.log("Dizi Grid Hatası:", err));

                }

            });



            // YATAY KAYDIRMA FONKSİYONU

            function scrollContainer(id, direction) {

                var container = document.getElementById(id);

                var scrollAmount = 300; 

                if(container) {

                    container.scrollBy({ left: direction * scrollAmount, behavior: 'smooth' });

                }

            }



            // 2. AJAX LOAD MORE FONKSİYONU

            function loadMorePosts() {

                var btn = document.getElementById('load-more-btn');

                var nextUrlDiv = document.getElementById('next-page-url');

                

                if(!nextUrlDiv || nextUrlDiv.textContent.trim() === "") {

                    btn.style.display = 'none';

                    return;

                }



                var url = nextUrlDiv.textContent.trim();

                btn.classList.add('loading');

                btn.innerHTML = "<i class='fas fa-spinner fa-spin'></i> YÜKLENİYOR...";



                fetch(url)

                .then(response => response.text())

                .then(data => {

                    var parser = new DOMParser();

                    var doc = parser.parseFromString(data, 'text/html');

                    

                    var newPosts = doc.querySelectorAll('.grid-movies .movie-card');

                    var mainGrid = document.getElementById('main-grid');

                    

                    if(newPosts.length > 0) {

                        newPosts.forEach(post => {

                            mainGrid.appendChild(post);

                        });

                        

                        enrichCards(mainGrid);

                    }



                    var nextLinkObj = doc.getElementById('next-page-url');

                    if(nextLinkObj && nextLinkObj.textContent.trim() !== "") {

                        nextUrlDiv.textContent = nextLinkObj.textContent.trim();

                        btn.classList.remove('loading');

                        btn.innerHTML = "<i class='fas fa-plus'></i> DAHA FAZLA YÜKLE";

                    } else {

                        btn.style.display = 'none';

                    }

                })

                .catch(err => {

                    console.log('Load More Error:', err);

                    btn.classList.remove('loading');

                    btn.innerHTML = "HATA OLUŞTU";

                });

            }



            // 3. Header Functions

            window.addEventListener('scroll', function() {

                var header = document.getElementById('main-header');

                if (window.scrollY > 50) header.classList.add('scrolled');

                else header.classList.remove('scrolled');

            });

            

            function toggleMenu() {

                document.getElementById('nav-menu').classList.toggle('active');

            }



            function toggleMobileSub(item) {

                // Sadece mobilde çalışsın

                if(window.innerWidth <= 768) {

                    item.classList.toggle('active-mobile');

                }

            }

