        window.addEventListener('scroll', function() {

            var header = document.getElementById('main-header');

            if (window.scrollY > 50) header.classList.add('scrolled');

            else header.classList.remove('scrolled');

        });

        

        // 2. Mobile Menu

        function toggleMenu() {

            document.getElementById('nav-menu').classList.toggle('active');

        }



        // 3. Benzer İçerikler

        window.addEventListener('load', function() {

            var engine = document.getElementById('related-engine');

            if(!engine) return;



            var label = engine.getAttribute('data-label');

            var encodedLabel = encodeURIComponent(label);

            var feedUrl = '/feeds/posts/default/-/' + encodedLabel + '?alt=json&max-results=6';



            fetch(feedUrl)

            .then(res => res.json())

            .then(data => {

                var entries = data.feed.entry;

                if(!entries || entries.length === 0) return;



                var html = "";

                var count = 0;

                var cleanCurrentUrl = window.location.href.split('?')[0].split('#')[0];



                for(var i=0; i<entries.length; i++){

                    var entry = entries[i];

                    

                    var entryLink = "";

                    for(var k=0; k<entry.link.length; k++){

                        if(entry.link[k].rel == 'alternate'){ 

                            entryLink = entry.link[k].href.split('?')[0].split('#')[0]; 

                            break; 

                        }

                    }



                    if(entryLink !== cleanCurrentUrl && count < 4){

                        var title = entry.title.$t;

                        var img = "https://via.placeholder.com/300x450?text=No+Img";



                        if (entry.content && entry.content.$t) {

                            var doc = new DOMParser().parseFromString(entry.content.$t, 'text/html');

                            var firstImg = doc.querySelector('img');

                            if(firstImg) {

                                img = firstImg.src; 

                            }

                        }

                        

                        if(img.includes("placeholder") && entry.media$thumbnail) {

                             img = entry.media$thumbnail.url.replace(/\/s[0-9]+(-c)?\//, '/w300-h450-c/');

                        }



                        html += `

                        <div class="movie-card" onclick="window.location.href='${entryLink}'">

                            <img class="poster-img" src="${img}" loading="lazy"/>

                            <div class="play-icon"><i class="fas fa-play-circle"></i></div>

                            <div class="card-info">

                                <div class="card-title">${title}</div>

                            </div>

                            <a href="${entryLink}" style="position:absolute; inset:0; z-index:20;"></a>

                        </div>`;

                        count++;

                    }

                }



                if(count > 0){

                    document.getElementById('related-grid').innerHTML = html;

                    engine.style.display = 'block';

                }

            })

            .catch(err => { console.log(err); });

        });



        // --- CANLI ARAMA SCRIPTI (Düzeltildi) ---

        document.addEventListener("DOMContentLoaded", function() {

            var searchInput = document.getElementById('search-input-field');

            var resultsBox = document.getElementById('live-search-results');

            var typingTimer; 

            var doneTypingInterval = 500; // Yarım saniye bekleme



            if (searchInput && resultsBox) {

                

                // Kullanıcı yazarken

                searchInput.addEventListener('keyup', function() {

                    clearTimeout(typingTimer);

                    if (searchInput.value.length > 2) {

                        typingTimer = setTimeout(doLiveSearch, doneTypingInterval);

                    } else {

                        resultsBox.classList.remove('active');

                    }

                });



                // Dışarı tıklayınca kapat

                document.addEventListener('click', function(e) {

                    if (!searchInput.contains(e.target) && !resultsBox.contains(e.target)) {

                        resultsBox.classList.remove('active');

                    }

                });



                function doLiveSearch() {

                    var query = searchInput.value;

                    resultsBox.innerHTML = '<div class="live-loading"><i class="fas fa-circle-notch fa-spin"></i> Aranıyor...</div>';

                    resultsBox.classList.add('active');



                    // Blogger JSON API

                    fetch('/feeds/posts/default?alt=json&q=' + encodeURIComponent(query) + '&max-results=5')

                    .then(function(response) { return response.json(); })

                    .then(function(data) {

                        var html = '';

                        if (data.feed.entry) {

                            data.feed.entry.forEach(function(entry) {

                                var title = entry.title.$t;

                                // Linki bul

                                var link = '';

                                for(var i=0; i<entry.link.length; i++) {

                                    if(entry.link[i].rel == 'alternate') { link = entry.link[i].href; break; }

                                }

                                

                                // Resmi bul

                                var img = 'https://via.placeholder.com/40x60?text=NA';

                                if (entry.media$thumbnail) {

                                    img = entry.media$thumbnail.url.replace('s72-c', 'w100-h150-c'); 

                                } else if(entry.content && entry.content.$t) {

                                     var doc = new DOMParser().parseFromString(entry.content.$t, 'text/html');

                                     var firstImg = doc.querySelector('img');

                                     if(firstImg) img = firstImg.src;

                                }



                                // Kategori

                                var cat = (entry.category && entry.category.length > 0) ? entry.category[0].term : 'Film';



                                html += '<a href="' + link + '" class="live-item">';

                                html += '<img src="' + img + '" class="live-thumb">';

                                html += '<div class="live-info">';

                                html += '<div class="live-title">' + title + '</div>';

                                html += '<div class="live-meta">' + cat + '</div>';

                                html += '</div></a>';

                            });

                        } else {

                            html = '<div class="live-loading">Sonuç bulunamadı.</div>';

                        }

                        resultsBox.innerHTML = html;

                    })

                    .catch(function(err) {

                        console.log(err);

                        resultsBox.innerHTML = '<div class="live-loading">Hata oluştu.</div>';

                    });

                }

            }

        });



